COMMENT ON COLUMN "public"."patient_snapshot_appointment_tags"."reason_code" IS 'Controlled reason code for why a scheduled ANC appointment was missed or should be removed from active follow-up.';
COMMENT ON COLUMN "public"."patient_snapshot_appointment_tags"."note" IS 'Optional free-text comment that adds context to the selected reason code.';
COMMENT ON TABLE "public"."patient_snapshot_appointment_tags" IS 'Stores follow-up tags for missed ANC appointments surfaced in Patient Snapshot so resolved missed visits can be hidden or separated.';

