-- ----------------------------
-- Function structure for generate_case_file_id
-- ----------------------------
DROP FUNCTION IF EXISTS "public"."generate_case_file_id"();
CREATE FUNCTION "public"."generate_case_file_id"()
  RETURNS "pg_catalog"."trigger" AS $BODY$
BEGIN
    NEW.case_file_id := (SELECT CONCAT(
        chr(trunc(65 + random() * 26)::int),
        chr(trunc(65 + random() * 26)::int),
        chr(trunc(65 + random() * 26)::int),
        trunc(random() * 1000000)::text
    ));
    RETURN NEW;
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100;

-- ----------------------------
-- Function structure for get_patient_stats
-- ----------------------------
DROP FUNCTION IF EXISTS "public"."get_patient_stats"("p_user_id" int4);
CREATE FUNCTION "public"."get_patient_stats"("p_user_id" int4)
  RETURNS TABLE("average" text, "youngest" text, "oldest" text, "median" text, "total_patients" int8) AS $BODY$
BEGIN
    RETURN QUERY
    WITH AgeStats AS (
        SELECT
            ROUND(AVG(EXTRACT(YEAR FROM AGE(dob)))) AS average,
            MIN(EXTRACT(YEAR FROM AGE(dob))) AS youngest,
            MAX(EXTRACT(YEAR FROM AGE(dob))) AS oldest,
            PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY EXTRACT(YEAR FROM AGE(dob))) AS median
        FROM
            patient_bio
        WHERE
            CASE WHEN p_user_id IS NOT NULL THEN assigned_user_id = p_user_id ELSE TRUE END
    )
    SELECT
        'Average: ' || (SELECT AgeStats.average::TEXT FROM AgeStats),
        'Youngest: ' || (SELECT AgeStats.youngest::TEXT FROM AgeStats),
        'Oldest: ' || (SELECT AgeStats.oldest::TEXT FROM AgeStats),
        'Median: ' || (SELECT AgeStats.median::TEXT FROM AgeStats),
        (SELECT COUNT(*) FROM patient_bio WHERE CASE WHEN p_user_id IS NOT NULL THEN assigned_user_id = p_user_id ELSE TRUE END);
END;
$BODY$
  LANGUAGE plpgsql VOLATILE
  COST 100
  ROWS 1000;

