    SELECT pg_catalog.regexp_matches( $1::pg_catalog.text, $2::pg_catalog.text, CASE WHEN pg_catalog.strpos($3, 'c') = 0 THEN  $3 || 'i' ELSE $3 END );
$BODY$
  LANGUAGE sql IMMUTABLE STRICT
  COST 100
  ROWS 10;

