INSERT INTO "public"."en_status" VALUES ('live system', '{"latest_version": "1.0.0", "download_url": "https://drive.google.com/file/d/1sQHDUOUcIy6qnx2wSG8iSbNL7oJyKjBz/view?usp=drive_link", "release_notes": "New features and bug fixes for antenatal section!", "release_date": "2025-05-12"}', '{
INSERT INTO "public"."feedback" VALUES ('f1006032-6b40-496c-a8a3-0a82a1992103', '4', 'testuser', 'Let''s add user notification', 'suggestion', 'review', '2025-07-24 12:57:30.441506', '2025-07-24 13:04:03.605078');
INSERT INTO "public"."health_tips" VALUES ('HT001', 'Eating a variety of nutritious foods is vital during pregnancy. Focus on fruits, vegetables, lean proteins, and whole grains to provide essential vitamins and minerals for both you and your baby. Good nutrition supports healthy fetal development and helps you maintain energy levels. Remember to stay hydrated by drinking plenty of water throughout the day. If you have specific dietary concerns, consult with a healthcare professional or a nutritionist.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT002', 'Regular, gentle exercise can be very beneficial during pregnancy. Activities like walking, swimming, or prenatal yoga can improve your mood, reduce back pain, and prepare your body for labor. Always listen to your body and avoid overexertion. If you experience any discomfort or unusual symptoms, stop and rest. Before starting any new exercise routine, it''s always best to talk to your doctor or midwife.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT003', 'Adequate rest is crucial for pregnant women. Aim for 7-9 hours of sleep each night. Naps during the day can also be helpful if you feel tired. Try to create a comfortable sleep environment and consider using pillows for support as your belly grows. Prioritizing rest helps your body recover and supports the immense changes happening within you. Don''t hesitate to ask for help with daily tasks if you need more time to rest.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT004', 'Attending all your prenatal appointments is extremely important. These visits allow healthcare professionals to monitor your health and your baby''s development, detect any potential issues early, and provide essential guidance. Don''t be afraid to ask questions or voice any concerns you may have during these appointments. Regular check-ups are key to a healthy pregnancy outcome for both mother and child.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT005', 'Avoid alcohol, smoking, and recreational drugs throughout your pregnancy. These substances can cause serious harm to your developing baby, leading to birth defects, premature birth, and developmental problems. Even small amounts can be detrimental. If you are struggling to quit, please reach out to your healthcare provider for support and resources. Your baby''s health depends on your choices.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT006', 'Stay hydrated by drinking plenty of clean and safe water throughout the day. Dehydration can lead to fatigue, headaches, and even premature contractions. Carry a water bottle with you and sip regularly, especially in Ghana''s warm climate. Aim for at least 8-10 glasses of water daily. Staying well-hydrated is essential for your overall health and the proper functioning of your body during pregnancy.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT007', 'Practicing good hygiene is vital to prevent infections. Wash your hands frequently with soap and water, especially before eating and after using the latrine. Keep your living area clean and tidy. Simple hygiene practices can significantly reduce your risk of common illnesses that could potentially affect your pregnancy. Protect yourself and your baby through these healthy habits.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT008', 'Recognize the signs of labor and know when to seek medical help. These can include regular contractions, a gush or trickle of fluid from your vagina, or persistent back pain. If you experience any of these, contact your healthcare provider or head to the nearest health facility immediately. Early recognition and prompt action are crucial for a safe delivery for both you and your baby.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT009', 'Ensure you have a birth plan, even if it''s simple. Discuss your preferences for labor and delivery with your healthcare provider. Think about who you want present, your pain management options, and what positions you might prefer. While not everything goes as planned, having a discussion helps you feel more prepared and in control during this important event. Communicate your wishes clearly.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT010', 'Prepare for breastfeeding even before your baby arrives. Learn about the benefits of breastfeeding for both you and your baby, and understand how to get started. Attend any available breastfeeding classes or speak with a lactation consultant. Breast milk provides essential nutrients and antibodies. Early preparation can make the breastfeeding journey smoother and more successful for you and your newborn.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT011', 'Manage stress effectively during pregnancy. High stress levels can impact your health and potentially affect your baby. Try relaxation techniques like deep breathing, spending time in nature, or listening to calming music. Talk to a trusted friend, family member, or your healthcare provider if you''re feeling overwhelmed. Taking care of your mental well-being is just as important as your physical health.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT012', 'Understand the importance of iron and folic acid supplements. These are often prescribed during pregnancy to prevent anemia and birth defects. Take them as directed by your healthcare provider. Iron helps carry oxygen to your baby, and folic acid is crucial for brain and spinal cord development. Consistent intake of these supplements is vital for a healthy pregnancy.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT013', 'Wear comfortable clothing and supportive shoes. As your body changes, comfort becomes increasingly important. Loose-fitting clothes made from breathable fabrics can help you stay cool and prevent discomfort. Supportive shoes can alleviate back pain and swelling. Prioritizing comfort allows you to move more freely and makes daily activities more manageable during your pregnancy journey.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT014', 'Be aware of warning signs during pregnancy that require immediate medical attention. These include severe headaches, blurred vision, sudden swelling in your face or hands, persistent abdominal pain, or reduced fetal movement. Do not hesitate to seek help if you experience any of these symptoms. Early intervention can prevent serious complications for both you and your baby.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT015', 'Prepare for the arrival of your baby by getting your home ready. This might involve organizing a space for the baby, gathering essential supplies like clothes and diapers, and ensuring a safe environment. While not every item is essential, having some preparations can reduce stress in the initial weeks after birth. Focus on the basics and what you truly need.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT016', 'Connect with other pregnant women or new mothers in your community. Sharing experiences and advice can be incredibly supportive and help you feel less alone. They can offer practical tips and emotional encouragement. Building a network can provide a valuable support system as you navigate the joys and challenges of pregnancy and motherhood.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT017', 'Discuss family planning options with your healthcare provider before and after delivery. Understanding contraception methods can help you space out your pregnancies, which is beneficial for your health and allows your body to recover. Informed decisions about family planning empower you to manage your reproductive health effectively and plan for your future.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT018', 'Protect yourself from malaria. Use insecticide-treated mosquito nets, especially when sleeping. If advised by your healthcare provider, take malaria prophylaxis. Malaria during pregnancy can be dangerous for both you and your baby. Taking preventive measures is crucial, especially in malaria-endemic areas like rural Ghana. Your vigilance protects your health and your baby''s.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT019', 'Limit your consumption of sugary drinks and processed foods. While cravings are common during pregnancy, focusing on healthier alternatives provides more sustained energy and better nutrition for your baby. Excessive sugar can lead to gestational diabetes and unhealthy weight gain. Choose fresh, whole foods whenever possible for optimal health outcomes.', '2025-07-18');
INSERT INTO "public"."health_tips" VALUES ('HT020', 'Understand the importance of postnatal care. After delivery, your body needs time to recover, and you and your baby will require ongoing check-ups. Attend all scheduled postnatal appointments. These visits are essential for monitoring your recovery, addressing any concerns, and ensuring your baby''s healthy development. Prioritizing postnatal care supports a strong start for both of you.', '2025-07-18');
