INSERT INTO "public"."message_list" VALUES (1101, 'Your baby is growing each day! Remember to visit the health center at your appointment times. Even if you feel well, these visits help doctors monitor you and the baby closely to ensure you are all doing well. ', 'Prenatal Care', 'Regular checkups');
INSERT INTO "public"."message_list" VALUES (1102, 'If you notice bleeding, severe headache, fever, baby not moving, or swelling in your face and hands, don''t wait! These may be serious signs. Go to the health center immediately. Quick action saves two lives - yours and your baby''s.', 'Prenatal Care', 'Danger signs');
INSERT INTO "public"."message_list" VALUES (1103, 'Malaria is dangerous during pregnancy. Always sleep under a treated mosquito net every night. If you feel fever, headache, or body pains, go to the clinic right away. The medicine they give is safe for your baby.', 'Prenatal Care', 'Malaria prevention');
INSERT INTO "public"."message_list" VALUES (1104, 'Feeling morning sickness? Try eating small amounts often instead of big meals. For backache, rest often and avoid heavy lifting. These discomforts will pass as your baby grows stronger.', 'Prenatal Care', 'Managing discomforts');
INSERT INTO "public"."message_list" VALUES (1201, 'It''s time to prepare for birth! Talk with your family about where you will deliver, how to get there, and who will accompany you. Being prepared brings peace of mind.', 'Birth Preparedness', 'Birth plan');
INSERT INTO "public"."message_list" VALUES (1202, 'Soon you will meet your baby. Labor has started when you feel regular pains that get stronger, waters break, or you see mucus with blood. When these signs come, follow your birth plan and go to your chosen health facility.', 'Birth Preparedness', 'Labor signs');
INSERT INTO "public"."message_list" VALUES (1203, 'As your time approaches, prepare these items: clean cloths, soap, clean blade for cord, warm clothes for baby, your health card, and money for transport. Having these ready makes birth day less stressful.', 'Birth Preparedness', 'Birth supplies');
INSERT INTO "public"."message_list" VALUES (1204, 'Have you arranged how to reach the health center when labor begins? Speak with a driver or neighbor with a vehicle now, before your time comes. Save their number in your phone. Don''t wait until labor starts!', 'Birth Preparedness', 'Transport planning');
INSERT INTO "public"."message_list" VALUES (1301, 'Your baby needs good food to grow strong. Try to eat kontomire, garden eggs, groundnuts, beans, and small fish daily. These local foods help your baby develop good brains and strong bones.', 'Nutrition And Health', 'Local nutritious foods');
INSERT INTO "public"."message_list" VALUES (1302, '“To prevent anemia and ensure a healthy pregnancy, eat dark green vegetables, beans and fruits. Also add meat or fish to your meals daily.', 'Nutrition And Health', 'Iron-rich foods');
INSERT INTO "public"."message_list" VALUES (1303, 'Remember to drink plenty of water throughout the day, even when not thirsty. Clean water helps your baby grow, prevents infections, and reduces headaches. Carry water with you when working in the fields.', 'Nutrition And Health', 'Hydration');
INSERT INTO "public"."message_list" VALUES (1304, 'Some say pregnant women shouldn''t eat eggs or snails, but these foods are very good for your baby''s growth. All foods from the clinic nutrition chart are safe and help your baby develop properly.', 'Nutrition And Health', 'Food taboos');
INSERT INTO "public"."message_list" VALUES (1401, 'Feeling worried is normal during pregnancy. When stress comes, try deep breathing - breathe in counting to four, out counting to four. Talk about your feelings with someone you trust. Your peace is baby''s peace.', 'Mental Health', 'Managing stress');
INSERT INTO "public"."message_list" VALUES (1402, 'After birth some women feel very sad or angry for no reason. This is not your fault and can be treated. If you cry often or cannot enjoy your baby, tell your health worker. Help is available.', 'Mental Health', 'Postpartum depression');
INSERT INTO "public"."message_list" VALUES (1403, 'Pregnancy is not a journey to walk alone. Identify a sister, mother, or friend who can listen to your concerns. Join the mothers'' group in your community. Together, the load becomes lighter.', 'Mental Health', 'Building support');
INSERT INTO "public"."message_list" VALUES (1404, 'During pregnancy, it''s important to take care of your emotional well-being. Make time for activities that help you relax. Speak with a trusted person if you need support.', 'Mental Health', 'Managing Emotions');
INSERT INTO "public"."message_list" VALUES (1501, 'Your first milk, yellow and thick, is perfect medicine for your newborn. Put baby to breast as soon as possible after delivery. Make sure baby''s mouth covers the dark part around your nipple for proper feeding.', 'Infant Care', 'Breastfeeding');
INSERT INTO "public"."message_list" VALUES (1502, 'Watch your newborn closely. If baby has difficulty breathing, feels too hot or too cold, refuses to breastfeed, or has yellow eyes, go to the health center immediately. Early care saves precious lives.', 'Infant Care', 'Newborn danger signs');
INSERT INTO "public"."message_list" VALUES (1503, 'Always wash hands with soap before touching your baby. Keep the cord stump clean and dry - no oils or herbs. Bathe the baby with warm water and mild soap. Clean hands keep your baby healthy.', 'Infant Care', 'Hygiene');
INSERT INTO "public"."message_list" VALUES (1504, 'Vaccines protect your baby from dangerous diseases. Take your baby for immunizations at birth when it is time. Even if your child seems healthy. These medicines are safe and free.', 'Infant Care', 'Immunizations');
INSERT INTO "public"."message_list" VALUES (1601, 'Smoke from cooking fires can harm you and your baby. When possible, cook outside or in well-ventilated areas. Let others cook for you sometimes. Your lungs need clean air to bring good oxygen to your baby.', 'Environmental Safety', 'Cooking smoke');
INSERT INTO "public"."message_list" VALUES (1602, 'Always drink water from safe sources like boreholes or treated water. If unsure, boil water for at least 1 minute and let it cool before drinking. Clean water prevents diarrhea and helps baby grow well.', 'Environmental Safety', 'Safe water');
INSERT INTO "public"."message_list" VALUES (1603, 'Your body is already working hard growing your baby. Take frequent rest breaks when farming or carrying loads. Ask family to help with heavy work. Listen to your body when it says ''rest now.''', 'Environmental Safety', 'Physical Strain');
INSERT INTO "public"."message_list" VALUES (1604, 'If you farm, avoid touching or breathing pesticides and chemicals. Ask others to apply them instead. If you must use them, wear gloves and wash hands well afterward. Some of these chemicals can harm your baby''s growth.', 'Environmental Safety', 'Pesticide safety');
INSERT INTO "public"."message_list" VALUES (1701, 'Some bleeding after birth is normal, but if you soak more than two pads in two hours, or pass large clots, go to the health center immediately. Quick action can save your life.', 'Postpartum Care', 'Bleeding warning');
INSERT INTO "public"."message_list" VALUES (1702, 'Your body needs time to heal after birth. Rest when baby rests. Normal recovery takes about six weeks, even if you feel better sooner. Be patient with your body - it has done amazing work!', 'Postpartum Care', 'Recovery time');
INSERT INTO "public"."message_list" VALUES (1703, 'Breastfeeding needs extra food and water. Eat one more meal each day than usual. Continue taking your iron tablets. Good foods for healing include soups, fruits, groundnuts, and plenty of water.', 'Postpartum Care', 'Postpartum nutrition');
INSERT INTO "public"."message_list" VALUES (1704, 'Remember to care for yourself too. Ask someone to watch baby while you bathe or rest. Wash your perineal area with clean water after using the toilet. Your health matters to your baby.', 'Postpartum Care', 'Self-care');
INSERT INTO "public"."message_list" VALUES (1801, 'You can become pregnant again even before your normal bleeding returns. Ask your health worker about family planning methods that are safe while breastfeeding. Planning helps keep both you and baby healthy.', 'Family Planning', 'Postpartum options');
INSERT INTO "public"."message_list" VALUES (1802, 'Did you know? Waiting at least 2 years before your next pregnancy is healthier for you and your children. Your body needs time to recover, and your new baby needs your full attention and breastmilk.', 'Family Planning', 'Birth spacing');
INSERT INTO "public"."message_list" VALUES (1803, 'Family planning works best when couples decide together. Find a quiet, private time to talk with your partner about your family''s future. The clinic can provide information for both of you.', 'Family Planning', 'Partner communication');
INSERT INTO "public"."message_list" VALUES (1804, 'Have you heard that family planning causes infertility? This is not true. Modern methods are temporary and safe. When you stop using them, fertility returns. The health worker can answer all your questions.', 'Family Planning', 'Myths and facts');
INSERT INTO "public"."message_list" VALUES (1901, 'Your baby''s father has an important role too. Invite him to clinic visits, share what you learn, and discuss baby''s needs together. When fathers are involved, mothers have less stress and babies grow better.', 'Family And Community Support', 'Male involvement');
INSERT INTO "public"."message_list" VALUES (1902, 'Have you met other pregnant women in your community? Try to form a small group to share experiences and support each other. Consider meeting from time to time to strengthen and share experiences.', 'Family And Community Support', 'Mother networks');
INSERT INTO "public"."message_list" VALUES (1903, 'Sometimes family members give different advice about pregnancy. Listen respectfully, but follow your health worker''s guidance for health matters. You can honor traditions while keeping baby safe.', 'Family And Community Support', 'Family dynamics');
INSERT INTO "public"."message_list" VALUES (1904, 'You have the right to respectful care at health facilities. Bring a support person to appointments if possible. If something doesn''t feel right, it''s okay to ask questions. Your voice matters.', 'Family And Community Support', 'Rights advocacy');
INSERT INTO "public"."message_list" VALUES (2001, 'If your local clinic refers you to the district hospital, it''s very important to go. This means you need special care not available at the clinic. The bigger hospital has equipment and specialists to help you.', 'Health System Navigation', 'Referral system');
INSERT INTO "public"."message_list" VALUES (2002, 'Always carry your maternal health card to every visit. This card holds important information about you and your baby. Health workers need this card to give you the best care possible.', 'Health System Navigation', 'Documents');
INSERT INTO "public"."message_list" VALUES (2003, 'Prepare questions before your clinic visit. Don''t be afraid to ask if you don''t understand something. You can say: ''Please explain again'' or ''Can you show me?'' Good care requires good communication.', 'Health System Navigation', 'Communication');
INSERT INTO "public"."message_list" VALUES (2004, 'Have you registered for the National Health Insurance? Pregnant women can register for free and receive free care. Ask your community health worker to help you apply. This card saves money when you need care.', 'Health System Navigation', 'Health insurance');
INSERT INTO "public"."message_list" VALUES (2101, 'When working, take breaks every hour to rest and drink water. Avoid chemicals, heavy lifting, and standing too long in one position. Your baby grows better when you pace your work wisely.', 'Practical Life Management', 'Work safety');
INSERT INTO "public"."message_list" VALUES (2102, 'As your pregnancy advances, rearrange home duties. Ask family members to help with fetching water, washing clothes, and cooking. Saving your strength now prepares you for labor and caring for your newborn.', 'Practical Life Management', 'Household management');
INSERT INTO "public"."message_list" VALUES (2103, 'Babies bring joy and also new expenses. Start setting aside small amounts now for delivery related costs, baby clothes, and emergency transport. Even small savings each week builds security for your family.', 'Practical Life Management', 'Financial planning');
INSERT INTO "public"."message_list" VALUES (2104, 'Planning your day can reduce stress. Spread your work in bits over the day so you do not get too tired, and prepare for tomorrow before sleeping. Good planning brings peace of mind.', 'Practical Life Management', 'Time management');
INSERT INTO "public"."message_list" VALUES (2201, 'Save these important numbers in your phone: your midwife, local driver, nearest health facility, and a family emergency contact. Make sure your phone is charged. These numbers can save precious time in emergencies.', 'Technology And Communication', 'Emergency contacts');
INSERT INTO "public"."message_list" VALUES (2202, 'Staying informed about your health is key to well-being. Reliable health information is available at your community health center. Make sure you are receiving information from qualified healthcare professionals.', 'Technology And Communication', 'Health information');
INSERT INTO "public"."message_list" VALUES (2203, 'Keep all health cards, test results, and medicine instructions in one safe place at home, protected from water and children. These records help health workers give you the best care throughout your pregnancy.', 'Technology And Communication', 'Record keeping');
INSERT INTO "public"."message_list" VALUES (2204, 'If you have questions or minor concerns between clinic appointments, your community health volunteer is available to help. Asking for help early can prevent problems from becoming larger.', 'Technology And Communication', 'Community health workers');
INSERT INTO "public"."message_list" VALUES (2301, 'Cervical cancer affects many women in Ghana but can be prevented and treated if found early. This cancer grows slowly in the cervix, giving time for screening to find it before it becomes dangerous. Regular check-ups can save your life.', 'Cervical Cancer Awareness', 'Basic awareness');
INSERT INTO "public"."message_list" VALUES (2302, 'Know the warning signs of cervical cancer: unusual bleeding between periods, bleeding after sex, pain during sex, or unusual discharge. If you notice any of these signs, visit a health center promptly. Early detection saves lives.', 'Cervical Cancer Awareness', 'Warning signs');
INSERT INTO "public"."message_list" VALUES (2303, 'Cervical cancer screening is simple and can find changes before cancer develops. Women should be screened every 3-5 years. After your baby is born and your body has recovered, ask about getting screened at your local health center.', 'Cervical Cancer Awareness', 'Screening importance');
INSERT INTO "public"."message_list" VALUES (2304, 'Most cervical cancer is caused by a common virus called HPV, which spreads through sexual contact. Having HPV is common and doesn''t mean you''ll get cancer, but regular screening helps find any changes early when treatment is simple.', 'Cervical Cancer Awareness', 'HPV education');
INSERT INTO "public"."message_list" VALUES (2305, 'Screening for cervical cancer is quick and not painful. Health workers may use vinegar to see if there are abnormal cells. This simple test can find problems years before cancer develops, when treatment is most effective.', 'Cervical Cancer Awareness', 'Screening methods');
INSERT INTO "public"."message_list" VALUES (2306, 'Some believe cervical cancer is caused by witchcraft or cannot be prevented. This is not true. It''s caused by a virus and can be prevented through screening. Modern medicine can detect and treat it early, before it becomes dangerous.', 'Cervical Cancer Awareness', 'Misconceptions');
INSERT INTO "public"."message_list" VALUES (2307, 'After childbirth and recovery, remember to include cervical cancer screening in your healthcare routine. The ideal time for screening is 6-12 months after delivery. Make this a regular part of caring for yourself as a mother.', 'Cervical Cancer Awareness', 'Post-pregnancy care');
INSERT INTO "public"."message_list" VALUES (2308, 'If screening finds abnormal cells, simple treatments are available at district hospitals. Early treatment is almost always successful. Don''t delay seeking care if referred for treatment. Your family needs you to stay healthy.', 'Cervical Cancer Awareness', 'Treatment options');
INSERT INTO "public"."message_list" VALUES (2309, 'As a mother, you can help protect your daughters from cervical cancer. When they are between 9-14 years old, HPV vaccination can prevent the virus that causes most cervical cancers. Ask your health worker about this important protection.', 'Cervical Cancer Awareness', 'Prevention for daughters');
INSERT INTO "public"."message_list" VALUES (2310, 'Early cervical cancer often has no symptoms. That''s why screening is important even when you feel healthy. As it progresses, you may notice bleeding after washing, heavier periods, or watery discharge. Don''t ignore these changes.', 'Cervical Cancer Awareness', 'Early-stage signs');
INSERT INTO "public"."message_list" VALUES (2311, 'Not all vaginal changes indicate cancer. However, bleeding after menopause, bleeding between periods, or bleeding after sex are never normal. Pain during sex or foul-smelling discharge should also be checked by a health worker.', 'Cervical Cancer Awareness', 'Distinguishing normal vs. abnormal');
INSERT INTO "public"."message_list" VALUES (2312, 'If you experience any unusual symptoms for more than two weeks, seek medical attention. Don''t wait until pain becomes severe or bleeding becomes heavy. Even if you''re embarrassed, health workers are trained to help with these concerns.', 'Cervical Cancer Awareness', 'When to seek help');
