INSERT INTO "public"."patient_messages" VALUES (1, '1', 'Always wash hands with soap before touching your baby. Keep the cord stump clean and dry - no oils or herbs. Bathe the baby with warm water and mild soap. Clean hands keep your baby healthy.', 'Infant Care', '2025-03-18 12:46:16.712862', 'delivered', '1503');
INSERT INTO "public"."patient_messages" VALUES (2, '1', 'Smoke from cooking fires can harm you and your baby. When possible, cook outside or in well-ventilated areas. Let others cook for you sometimes. Your lungs need clean air to bring good oxygen to your baby.', 'Environmental Safety', '2025-03-18 12:46:16.712862', 'delivered', '1601');
INSERT INTO "public"."patient_messages" VALUES (3, '1', 'Remember to care for yourself too. Ask someone to watch baby while you bathe or rest. Wash your perineal area with clean water after using the toilet. Your health matters to your baby.', 'Postpartum Care', '2025-03-18 12:46:16.712862', 'delivered', '1704');
INSERT INTO "public"."patient_messages" VALUES (4, '2', 'Always wash hands with soap before touching your baby. Keep the cord stump clean and dry - no oils or herbs. Bathe the baby with warm water and mild soap. Clean hands keep your baby healthy.', 'Infant Care', '2025-03-18 12:46:16.712862', 'delivered', '1503');
