INSERT INTO "public"."patient_messages" VALUES (1314, '1434', 'Remember to care for yourself too. Ask someone to watch baby while you bathe or rest. Wash your perineal area with clean water after using the toilet. Your health matters to your baby.', 'Postpartum Care', '2025-03-18 12:46:16.712862', 'delivered', '1704');
